<article class="min-w-0 print:[&_a]:text-black" data-docs-article><header class="mb-10 border-b border-[var(--border)] pb-[30px] pt-1"><div class="mb-3 flex items-center gap-2 text-xs font-semibold uppercase tracking-[.06em] text-[var(--brand-strong)]"><span>Private operations</span><span class="inline-flex items-center rounded-full border border-[color-mix(in_srgb,#f59e0b_24%,var(--border))] bg-[var(--warn-soft)] px-[7px] py-1 text-[11px] font-[650] normal-case tracking-normal text-[var(--warn)]">Authenticated</span></div><h1 class="m-0 max-w-[760px] text-[clamp(2rem,4vw,2.72rem)] font-[760] leading-[1.08] tracking-[-.045em] text-[var(--text-strong)] text-balance">Infrastructure inventory</h1><p class="mt-[15px] max-w-[660px] text-[17px] leading-[1.65] text-[var(--muted)]">A live index generated from service metadata in your Markdown frontmatter.</p><div class="mt-3.5 flex items-center gap-[9px] text-[13px] text-[var(--faint)]"><span><?= count($services) ?> documented service<?= count($services) === 1 ? '' : 's' ?></span></div></header>
<?php if ($services): ?><div class="overflow-hidden rounded-[var(--radius-lg)] border border-[var(--border)] bg-[var(--surface)] shadow-sm max-[700px]:overflow-auto"><div class="grid min-h-9 min-w-[680px] grid-cols-[70px_minmax(150px,1.5fr)_minmax(130px,1fr)_minmax(120px,1fr)_minmax(100px,.8fr)] items-center gap-3 border-b border-[var(--border)] bg-[var(--surface-subtle)] px-[13px] py-2 text-[11px] font-bold uppercase tracking-[.07em] text-[var(--faint)]"><span>ID</span><span>Application</span><span>Address</span><span>Installation</span><span>Review</span></div><?php foreach ($services as $item): $page = $item['page']; $service = $item['service']; ?><a class="grid min-h-[58px] min-w-[680px] grid-cols-[70px_minmax(150px,1.5fr)_minmax(130px,1fr)_minmax(120px,1fr)_minmax(100px,.8fr)] items-center gap-3 border-b border-[var(--border)] px-[13px] py-[9px] text-xs last:border-b-0 hover:bg-[var(--surface-subtle)]" href="<?= $e($page->url) ?>"><span><?= isset($service['id']) ? 'CT ' . $e($service['id']) : '—' ?></span><span class="grid"><strong class="text-[13px]"><?= $e($service['application'] ?? $page->title) ?></strong><small class="text-xs text-[var(--faint)]"><?= $e($service['type'] ?? 'service') ?></small></span><span><code class="font-mono text-[11px]"><?= $e($service['address'] ?? '—') ?></code></span><span><?= $e($service['installation'] ?? 'documented') ?></span><span class="<?= $page->isReviewStale() ? 'text-[var(--warn)]' : '' ?>"><?= $page->reviewedAt() ? $e(date('M j, Y', $page->reviewedAt())) : 'Not reviewed' ?></span></a><?php endforeach; ?></div><?php else: ?><div class="rounded-[calc(var(--radius)+2px)] border border-dashed border-[var(--border-strong)] bg-[var(--surface-subtle)] px-5 py-[55px] text-center"><h2 class="m-0">No services documented yet</h2><p class="mt-1 text-[var(--muted)]">Add a `service` mapping to page frontmatter.</p></div><?php endif; ?>
</article>
